def process_graph(graph_data):

    # Create a copy of the graph
    graph_copy = copy.deepcopy(graph_data)

    # Add new PACKET_SWITCH node
    graph_copy.add_node('new_EK_PACKET_SWITCH_8', type=['EK_PACKET_SWITCH'], name='new_EK_PACKET_SWITCH_8')
    graph_copy.add_edge('ju1.a2.m4', 'new_EK_PACKET_SWITCH_8', type=['RK_CONTAINS'])

    # Find the parent node ju1.a2.m4
    parent_node = None
    for node in graph_copy.nodes(data=True):
        if node[1].get('name') == 'ju1.a2.m4':
            parent_node = node[0]
            break

    # Function to calculate total capacity of a node
    def calculate_capacity(node_id, graph):
        total_capacity = 0
        # If it's a PORT node, return its physical capacity
        node_data = graph.nodes[node_id]
        if 'EK_PORT' in node_data.get('type', []):
            return node_data.get('physical_capacity_bps', 0)

        # Otherwise, recursively sum capacities of all contained PORTs
        for successor in graph.successors(node_id):
            edge_data = graph.get_edge_data(node_id, successor)
            if edge_data and 'RK_CONTAINS' in edge_data.get('type', []):
                total_capacity += calculate_capacity(successor, graph)
        return total_capacity

    # Collect direct children of parent node and their capacities
    child_capacities = []
    if parent_node:
        for child in graph_copy.successors(parent_node):
            edge_data = graph_copy.get_edge_data(parent_node, child)
            if edge_data and 'RK_CONTAINS' in edge_data.get('type', []):
                child_name = graph_copy.nodes[child].get('name', child)
                capacity = calculate_capacity(child, graph_copy)
                child_capacities.append((child_name, capacity))

    # Sort by capacity descending
    child_capacities.sort(key=lambda x: x[1], reverse=True)

    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)
    return_object = {
        'type': 'list',
        'data': child_capacities,
        'updated_graph': graph_json
    }
    return return_object

